import React, { useState, useEffect } from 'react';
import './EditOutflow.css';

const EditOutflow = ({outflow, handleUpdate, handleCancel }) => {
  
  const [materials, setMaterials] = useState([]);
  const [purchases, setPurchases] = useState([]);
  const [locations, setLocations] = useState([]);
  const [projects, setProjects] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [outflows, setOutflows] = useState([]);

  const [editedOutflow, setEditedOutflow] = useState({ ...outflow });
  const [showExtras, setShowExtras] = useState(
    (outflow.width)
  );
  console.log('OUTFLOWMAT', outflow);
  console.log('xtras', showExtras);

  

  useEffect(() => {
    if (editedOutflow.location && editedOutflow.materialid && editedOutflow.quantity && !showExtras) {
      try {
        const filteredPurchases = purchases.filter(pur =>
          pur.location === editedOutflow.location &&
          pur.materialid === editedOutflow.materialid
        );
        console.log("Filtered Purchases:", filteredPurchases);
      
        const filteredOutflows = outflows.filter(out =>
          out.location === editedOutflow.location &&
          out.materialid === editedOutflow.materialid
        );
        console.log("Filtered Outflows:", filteredOutflows);
      
        // Calculate sum of previous outflows
        const totalPreviousOutflows = filteredOutflows.reduce((sum, out) => sum + parseFloat(out.quantity), 0);
        console.log("Sum of previous outflows:", totalPreviousOutflows);
      
        let sumOfQuantities = 0;
        let totalCost = 0;
        let remainingOutflowQuantity = editedOutflow.quantity;
        let remQuant = 0;
      
        for (const purchase of filteredPurchases) {
          const purchaseQuantity = parseFloat(purchase.quantity);
          const purchasePrice = parseFloat(purchase.price);
          console.log("purchase:", purchase);
          console.log("purchaseQuantity:", purchaseQuantity);
          console.log("purchasePrice:", purchasePrice);
          sumOfQuantities += purchaseQuantity;
          remQuant = sumOfQuantities - totalPreviousOutflows;
          console.log("remQuantfinal:", remQuant);
      
          if (sumOfQuantities >= totalPreviousOutflows) {
            if (remainingOutflowQuantity <= remQuant) {
              console.log("outflow quantity inside k:", remainingOutflowQuantity);
              console.log("remQuant quantity inside k:", remQuant);
              totalCost += remainingOutflowQuantity * purchasePrice;
              console.log("totalcost:", totalCost);
              break;
            } else {
              console.log("outflow quantity inside k:", remainingOutflowQuantity);
              console.log("remQuant quantity inside k:", remQuant);
              totalCost += remQuant * purchasePrice;
              console.log("totalcost:", totalCost);
              remainingOutflowQuantity -= remQuant;
            }
            continue;
          }
    
        }
        setEditedOutflow((prevPurchase) => ({
          ...prevPurchase,
          cost: totalCost,
        }));
      
        console.log("totalcostfinal:", totalCost);

      } catch (error) {
        console.error('Error calculating cost:', error);
      }
    }  else if (editedOutflow.lotnumber) {
      setEditedOutflow((prevPurchase) => ({
        ...prevPurchase,
        cost: purchases.find((pur) => pur.materialid=== editedOutflow.materialid && pur.lotnumber === editedOutflow.lotnumber).price * editedOutflow.width* editedOutflow.quantity

      }));

    }

    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [materialResponse, purchaseResponse, locationResponse, projectResponse, employeesResponse, outflowsResponse] = await Promise.all([
        fetch('http://localhost:8081/materiallist').then((response) => response.json()),
        fetch('http://localhost:8081/PurchasesAPI').then((response) => response.json()),
        fetch('http://localhost:8081/LocationsAPI').then((response) => response.json()),
        fetch('http://localhost:8081/projectsAPI').then((response) => response.json()),
        fetch('http://localhost:8081/employeesAPI').then((response) => response.json()),
        fetch('http://localhost:8081/outflowsAPI').then((response) => response.json()),
      ]);
  
      setMaterials(materialResponse);
      setPurchases(purchaseResponse);
      setLocations(locationResponse);
      setProjects(projectResponse);
      setEmployees(employeesResponse);
      setOutflows(outflowsResponse);

     
    } catch (error) {
      console.log('Error fetching data:', error);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
  
    if (name === 'location') {
      setEditedOutflow((prevEditedOutflow) => ({
        ...prevEditedOutflow,
        [name]: parseInt(value),
        materialid: '',
        materialname: '',
        width: null,
        lotnumber: '',
      }));
    } else if (name === 'materialid') {
      const selectedMaterial = materials.find((material) => material.matid === value);
      console.log('matextras',selectedMaterial);  
      if (selectedMaterial) {
        setEditedOutflow((prevEditedOutflow) => ({
          ...prevEditedOutflow,
          [name]: value,
          lotnumber: '',
          width: null,
        }));
        setShowExtras(selectedMaterial.extras === 1);
        console.log('extras', showExtras);
      }
    } else if (name === 'employee') {
      setEditedOutflow((prevEditedOutflow) => ({
        ...prevEditedOutflow,
        [name]: parseInt(value),
      }));
    } else if (name === 'project') {
      setEditedOutflow((prevEditedOutflow) => ({
        ...prevEditedOutflow,
        [name]: parseInt(value),
      }));
    } else {
      setEditedOutflow((prevEditedOutflow) => ({
        ...prevEditedOutflow,
        [name]: value,
      }))};

  };
  

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      handleUpdate(editedOutflow); // Pass the outflowid parameter here
      setShowExtras(false);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  const handleCancelClick = () => {
    handleCancel(); // Call the cancel function passed as a prop
  };
  

  const availableMaterials = () => {
    if (editedOutflow.location) {
      const filteredMaterials = purchases.filter((purchase) => purchase.location === editedOutflow.location);
      const uniqueMaterialIds = Array.from(new Set(filteredMaterials.map((purchase) => purchase.materialid)));
      return uniqueMaterialIds;
    }
    return [];
  };

  return (
    <form onSubmit={handleSubmit} className="edit-outflow-form">
    <div>
      <label>Location:</label>
      <select name="location" value={editedOutflow.location || ''} onChange={handleChange} required>
        <option value="">Select a location</option>
        {locations.map((location) => (
          <option key={location.id} value={location.id}>
            {location.locationname}
          </option>
        ))}
      </select>
    </div>
    {editedOutflow.location && (
      <div>
        <div>
          <label>Material ID:</label>
          <select
            name="materialid"
            value={editedOutflow.materialid || ''}
            onChange={handleChange}
            required
          >
            <option value="">Select a material</option>
            {availableMaterials().map(materialid => (
              <option key={materialid} value={materialid}>
                {materialid}
              </option>
            ))}
          </select>
        </div>
        <div>
          <label>Material Name:</label>
          <input
            type="text"
            name="materialname"
            value={
              materials.find((material) => material.matid === editedOutflow.materialid)?.name || 'Material not found'
            }
            readOnly
            required
          />
        </div>
      </div>
    )}
    {showExtras && editedOutflow.materialid &&(
      <div>
      <label>Width:</label>
      <select
        type="number"
        name="width"
        value={editedOutflow.width || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a width</option>
        {Array.from(
          new Set(
            purchases
              .filter(
                (purchase) =>
                  purchase.location === editedOutflow.location &&
                  purchase.materialid === editedOutflow.materialid
              )
              .map((purchase) => purchase.width)
          )
        ).map((width) => (
          <option key={width} value={width}>
            {width}
          </option>
        ))}
      </select>
    </div>  
    )}
    {showExtras && editedOutflow.width && (
      <div>
      <label>Lot No:</label>
      <select
        name="lotnumber"
        value={editedOutflow.lotnumber || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a Lot Number</option>
        {Array.from(
          new Set(
            purchases
              .filter(
                (purchase) =>
                  purchase.location === editedOutflow.location &&
                  purchase.materialid === editedOutflow.materialid &&
                  purchase.width === editedOutflow.width
              )
              .map((purchase) => purchase.lotnumber)
          )
        ).map((lotnumber) => (
          <option key={lotnumber} value={lotnumber}>
            {lotnumber}
          </option>
        ))}
      </select>
    </div>
    )}
    {showExtras && editedOutflow.lotnumber && (
      <div>
        <label>Quantity:</label>
        <input type="number" name="quantity" value={editedOutflow.quantity || ''} onChange={handleChange} required />
      </div>
    )}
    {!showExtras && editedOutflow.materialid && (
      <div>
        <label>Quantity:</label>
        <input type="number" name="quantity" value={editedOutflow.quantity || ''} onChange={handleChange} required />
      </div>
    )}
    {editedOutflow.quantity && (
    <div>
      <label>Employee:</label>
      <select
        name="employee"
        value={editedOutflow.employee || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select an Employee</option>
        {employees.map((employee) => (
          <option key={employee.empid} value={employee.empid}>
            {employee.name}
          </option>
        ))}
      </select>
    </div>
    )}
    {editedOutflow.employee && (
    <div>
      <label>Project:</label>
      <select
        name="project"
        value={editedOutflow.project || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a Project</option>
        {projects.map((project) => (
          <option key={project.prid} value={project.prid}>
            {project.name}
          </option>
        ))}
      </select>
    </div>
    )}
    <div className="btn-container">
        <button type="submit" className="add-purchase-btn">
          Add Outflow
        </button>
        <button type="button" className="cancel-btn" onClick={handleCancelClick}>
          Cancel
        </button>
      </div>
    </form>
);
};

export default EditOutflow;
